	}
	if len(ips) == 0 {
		return fmt.Errorf("Failed to resolve host")
	}
	for _, ip := range ips {
		if isPrivateOrLocalIP(ip) {
			return fmt.Errorf("Blocked IP")
		}
	}
	return nil
