// denyPrivateHost resolves host and rejects private/loopback/link-local/multicast/unspecified IPs.
// Also rejects obvious local hostnames.
func denyPrivateHost(host string) error {
	h := strings.ToLower(strings.TrimSpace(host))
	if h == "localhost" || strings.HasSuffix(h, ".localhost") || h == "local" || strings.HasSuffix(h, ".local") {
		return errors.New("host is not allowed")
	}

	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return errors.New("unable to resolve host")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return errors.New("host resolves to a disallowed IP range")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize IPv4-mapped IPv6 to IPv4 when applicable.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	} else if v16 := ip.To16(); v16 != nil {
		ip = v16
	} else {
		return true
	}

	// Go helpers
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}

	// Additional IPv6 special ranges (defense-in-depth).
	if ip.To16() != nil && ip.To4() == nil {
		// Unique local: fc00::/7
		if ip[0]&0xfe == 0xfc {
			return true
		}
	}
	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	inTitle := false
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				title = strings.TrimSpace(title)
				description = strings.TrimSpace(description)
				if len(title) > maxTitleLen {
					title = title[:maxTitleLen]
				}
				if len(description) > maxDescLen {
					description = description[:maxDescLen]
				}
				return title, description, nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			tag := strings.ToLower(t.Data)

			if tag == "title" && tt == html.StartTagToken {
				inTitle = true
				continue
			}

			if tag == "meta" {
				var name, property, content string
				for _, a := range t.Attr {
					key := strings.ToLower(a.Key)
					val := strings.TrimSpace(a.Val)
					switch key {
					case "name":
						name = strings.ToLower(val)
					case "property":
						property = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				// Prefer standard meta description, fallback to og:description.
				if description == "" {
					if name == "description" && content != "" {
						description = content
					} else if property == "og:description" && content != "" {
						description = content
					}
				}
			}

		case html.EndTagToken:
			t := z.Token()
			if strings.ToLower(t.Data) == "title" {
				inTitle = false
			}

		case html.TextToken:
			if inTitle && title == "" {
				title = string(z.Text())
			}
		}
	}
}

