func writeJSON(ctx *fasthttp.RequestCtx, status int, v any) {
	ctx.SetStatusCode(status)
	ctx.Response.Header.SetContentType("application/json; charset=utf-8")
	enc := json.NewEncoder(ctx)
	_ = enc.Encode(v)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, previewResponse{Error: "method not allowed"})
		return
	}

	var req previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: "invalid json body"})
		return
	}
	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: "url is required"})
		return
	}

	parsed, err := url.Parse(req.URL)
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: "invalid url"})
		return
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: "only http/https urls are allowed"})
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	var fReq fasthttp.Request
	var fResp fasthttp.Response
	fReq.Header.SetMethod(fasthttp.MethodGet)
	fReq.SetRequestURI(req.URL)
	fReq.Header.SetUserAgent("url-preview-bot/1.0")
	fReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// 3 seconds total timeout for fetching content
	timeout := 3 * time.Second
	if err := client.DoTimeout(&fReq, &fResp, timeout); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, previewResponse{URL: req.URL, Error: "fetch failed: " + err.Error()})
		return
	}

	status := fResp.StatusCode()
	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, previewResponse{URL: req.URL, Error: "upstream status: " + fasthttp.StatusMessage(status)})
		return
	}

	ct := strings.ToLower(string(fResp.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml") {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, previewResponse{URL: req.URL, Error: "content is not html"})
		return
	}

	body := fResp.Body()
	// Basic size guard (avoid huge pages)
	const maxBody = 2 << 20 // 2 MiB
	if len(body) > maxBody {
		body = body[:maxBody]
	}

	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(body))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, previewResponse{URL: req.URL, Error: "html parse failed"})
		return
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())
	desc, _ := doc.Find(`meta[name="description"]`).First().Attr("content")
	if desc == "" {
		desc, _ = doc.Find(`meta[property="og:description"]`).First().Attr("content")
	}
	desc = strings.TrimSpace(desc)

	// fasthttp doesn't reliably expose the final URL after redirects; keep original.
	finalURL := req.URL

	writeJSON(ctx, fasthttp.StatusOK, previewResponse{
		URL:         req.URL,
		FinalURL:    finalURL,
		Title:       title,
		Description: desc,
	})
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetContentType("text/plain; charset=utf-8")
			ctx.SetBodyString("not found")
		}
	}

	log.Println("listening on :8080 (POST /preview {\"url\":\"https://example.com\"})")
	if err := fasthttp.ListenAndServe(":8080", h); err != nil {
		log.Fatal(err)
	}
}

