package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: "Invalid JSON"})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: "URL is required"})
		return
	}

	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: "Invalid URL format"})
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: "URL must use http or https scheme"})
		return
	}

	// SSRF protection: block localhost, private, link-local, multicast, etc.
	if err := validateNoSSRF(parsedURL); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: err.Error()})
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	const maxRedirectCounts = 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		return
	}

	if res.StatusCode() < 200 || res.StatusCode() >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", res.StatusCode())})
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{Error: "Empty response body"})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusInternalServerError, PreviewResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, v any) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	b, err := json.Marshal(v)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
	ctx.SetBody(b)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := goquery.NewDocumentFromReader(r)
	if err != nil {
		return "", "", err
	}

	title = strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description, then OG/twitter fallbacks.
	if v, ok := doc.Find(`meta[name="description"]`).First().Attr("content"); ok {
		description = strings.TrimSpace(v)
	}
	if description == "" {
		if v, ok := doc.Find(`meta[property="og:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}
	if description == "" {
		if v, ok := doc.Find(`meta[name="twitter:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}

	return title, description, nil
}

func validateNoSSRF(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return fmt.Errorf("Invalid URL host")
	}

	// Block obvious localhost names.
	h := strings.ToLower(strings.TrimSuffix(host, "."))
	if h == "localhost" || h == "localhost.localdomain" {
		return fmt.Errorf("URL host is not allowed")
	}

	// Block credentials in URL.
	if u.User != nil {
		return fmt.Errorf("URL credentials are not allowed")
	}

	// Resolve and validate all IPs.
	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return fmt.Errorf("Unable to resolve host")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return fmt.Errorf("URL host is not allowed")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// net.IP.Unmap() exists only in newer Go versions. Use To4() to normalize
	// IPv4-mapped IPv6 addresses instead.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}

	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}

	// IPv4 checks
	if v4 := ip.To4(); v4 != nil {
		switch {
