func writeJSON(ctx *fasthttp.RequestCtx, status int, v any) {
	ctx.SetStatusCode(status)
	ctx.Response.Header.SetContentType("application/json; charset=utf-8")
	enc := json.NewEncoder(ctx)
	enc.SetEscapeHTML(true)
	_ = enc.Encode(v)
}

func normalizeAndValidateURL(raw string) (string, error) {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return "", errors.New("url is required")
	}
	u, err := url.Parse(raw)
	if err != nil {
		return "", errors.New("invalid url")
	}
	if u.Scheme == "" {
		u, err = url.Parse("https://" + raw)
		if err != nil {
			return "", errors.New("invalid url")
		}
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		return "", errors.New("only http and https schemes are allowed")
	}
	if u.Host == "" {
		return "", errors.New("invalid url host")
	}
	return u.String(), nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, fetchResponse{Error: "method not allowed"})
		return
	}

	var req fetchRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchResponse{Error: "invalid json body"})
		return
	}

	target, err := normalizeAndValidateURL(req.URL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchResponse{Error: err.Error()})
		return
	}

	// Timeout MUST be 3 seconds.
	timeout := 3 * time.Second

	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         timeout,
		WriteTimeout:        timeout,
		MaxConnWaitTimeout:  timeout,
		MaxIdleConnDuration: 10 * time.Second,
	}

	freq := fasthttp.AcquireRequest()
	fresp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(fresp)

	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.SetRequestURI(target)
	freq.Header.SetUserAgent("url-preview/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// MUST use DoRedirects.
	if err := client.DoRedirects(freq, fresp, 10); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
			URL:   target,
			Error: "failed to fetch url: " + err.Error(),
		})
		return
	}

	status := fresp.StatusCode()
	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
			URL:   target,
			Error: "upstream returned status " + fasthttp.StatusMessage(status),
		})
		return
	}

	ct := strings.ToLower(string(fresp.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, fetchResponse{
			URL:   target,
			Error: "unsupported content-type: " + ct,
		})
		return
	}

	body := fresp.Body()
	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(body))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
			URL:   target,
			Error: "failed to parse html: " + err.Error(),
		})
		return
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	desc := ""
	if s := doc.Find(`meta[name="description"]`).First(); s.Length() > 0 {
		if c, ok := s.Attr("content"); ok {
			desc = strings.TrimSpace(c)
		}
	}
	if desc == "" {
		if s := doc.Find(`meta[property="og:description"]`).First(); s.Length() > 0 {
			if c, ok := s.Attr("content"); ok {
				desc = strings.TrimSpace(c)
			}
		}
	}

	// After redirects, RequestURI contains the final URL.
	finalURL := string(freq.URI().FullURI())

	resp := fetchResponse{
		URL:         target,
		FinalURL:    finalURL,
		Title:       title,
		Description: desc,
	}

	writeJSON(ctx, fasthttp.StatusOK, resp)
}

func main() {
	mux := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetContentType("application/json; charset=utf-8")
			_, _ = ctx.WriteString(`{"error":"not found"}` + "\n")
		}
	}

	addr := ":8080"
	log.Printf("listening on %s", addr)
	if err := fasthttp.ListenAndServe(addr, mux); err != nil {
		log.Fatal(err)
	}
}

