		}
		// 192.0.0.0/24
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 0 {
			return true
		}
		// 198.18.0.0/15 (benchmark)
		if ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19) {
			return true
		}
		// 224.0.0.0/4 multicast and 240.0.0.0/4 reserved
		if ip4[0] >= 224 {
			return true
		}
		return false
	}

	// IPv6 checks
	if ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}
	// fc00::/7 unique local
	if len(ip) == net.IPv6len && (ip[0]&0xFE) == 0xFC {
		return true
	}
	// fe80::/10 link-local
	if len(ip) == net.IPv6len && ip[0] == 0xFE && (ip[1]&0xC0) == 0x80 {
		return true
	}
	return false
}

func validateTarget(raw string) (*url.URL, error) {
	parsed, err := url.Parse(strings.TrimSpace(raw))
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		return nil, errors.New("invalid url")
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return nil, errors.New("only http/https urls are supported")
	}
	if parsed.User != nil {
		return nil, errors.New("userinfo not allowed")
	}

	host := parsed.Hostname()
	if host == "" {
		return nil, errors.New("invalid host")
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, errors.New("target is not allowed")
		}
		return parsed, nil
	}

	// Block obvious local hostnames.
	lh := strings.ToLower(host)
	if lh == "localhost" || strings.HasSuffix(lh, ".localhost") || lh == "localhost." {
		return nil, errors.New("target is not allowed")
	}

	// Resolve and ensure all resolved IPs are public.
	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return nil, errors.New("failed to resolve host")
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, errors.New("target is not allowed")
		}
	}
	return parsed, nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, previewResponse{Error: "method not allowed"})
		return
	}

	var req previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: "invalid json body"})
		return
	}

	raw := strings.TrimSpace(req.URL)
	if raw == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: "url is required"})
		return
	}

	parsed, err := validateTarget(raw)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, previewResponse{Error: err.Error()})
		return
	}

	client := &fasthttp.Client{
		// Use a dialer that re-validates the resolved IP to prevent DNS rebinding.
		Dial: func(addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				// If addr is missing port, fall back to default parsing.
				host = addr
				port = ""
			}
			if host == "" {
				return nil, errors.New("invalid address")
			}
			if ip := net.ParseIP(host); ip != nil {
				if isPrivateIP(ip) {
					return nil, errors.New("blocked address")
				}
			} else {
				ips, err := net.LookupIP(host)
				if err != nil || len(ips) == 0 {
					return nil, errors.New("failed to resolve host")
				}
				for _, ip := range ips {
					if isPrivateIP(ip) {
						return nil, errors.New("blocked address")
					}
				}
			}

			if port == "" {
				// Should not happen with fasthttp, but keep safe.
				if parsed.Scheme == "https" {
					port = "443"
				} else {
					port = "80"
				}
			}
			return fasthttp.DialTimeout(net.JoinHostPort(host, port), 5*time.Second)
		},
		ReadTimeout:         8 * time.Second,
		WriteTimeout:        8 * time.Second,
		MaxConnsPerHost:     16,
		MaxIdleConnDuration: 15 * time.Second,
	}

	freq := fasthttp.AcquireRequest()
	fresp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(fresp)

	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.SetRequestURI(parsed.String())
	freq.Header.Set("User-Agent", "url-preview/1.0 (+fasthttp)")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Required by task: use DoRedirects
	if err := client.DoRedirects(freq, fresp, 5); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, previewResponse{URL: raw, Error: "fetch failed: " + err.Error()})
		return
	}

	status := fresp.StatusCode()
	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, previewResponse{URL: raw, Error: "upstream returned status " + fasthttp.StatusMessage(status)})
		return
	}

	ct := strings.ToLower(string(fresp.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, previewResponse{URL: raw, Error: "content is not html"})
		return
	}

	body := fresp.Body()
	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(body))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, previewResponse{URL: raw, Error: "failed to parse html"})
		return
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	desc := ""
	if s := doc.Find(`meta[name="description"]`).First(); s != nil {
		if v, ok := s.Attr("content"); ok {
			desc = strings.TrimSpace(v)
		}
	}
	if desc == "" {
		if s := doc.Find(`meta[property="og:description"]`).First(); s != nil {
			if v, ok := s.Attr("content"); ok {
				desc = strings.TrimSpace(v)
			}
		}
	}

	// fasthttp doesn't expose final URL reliably; keep empty unless explicitly set.
	writeJSON(ctx, fasthttp.StatusOK, previewResponse{
		URL:         raw,
		FinalURL:    "",
		Title:       title,
		Description: desc,
	})
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetContentType("application/json; charset=utf-8")
			_, _ = ctx.WriteString(`{"error":"not found"}` + "\n")
		}
	}

	log.Println("listening on :8080")
	if err := fasthttp.ListenAndServe(":8080", h); err != nil {
		log.Fatal(err)
	}
}

