func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	ip = ip.To4()
	if ip == nil {
		// Treat IPv6 as private for safety in this context.
		return true
	}
	// 127.0.0.0/8
	if ip[0] == 127 {
		return true
	}
	// 10.0.0.0/8
	if ip[0] == 10 {
