// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	var (
		inTitle     bool
		depth       int
		tokenWalked int
	)

	for {
		tokenWalked++
		if tokenWalked > maxHTMLTokenWalk {
			break
		}

		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return truncate(title, maxTitleLen), truncate(description, maxDescriptionLen), nil
			}
			return "", "", z.Err()

		case html.StartTagToken:
			depth++
			if depth > maxHTMLDepth {
				return truncate(title, maxTitleLen), truncate(description, maxDescriptionLen), nil
			}

			tok := z.Token()
			tag := strings.ToLower(tok.Data)

			if tag == "title" {
				inTitle = true
				continue
			}

			if tag == "meta" && description == "" {
				var name, prop, content string
				for _, a := range tok.Attr {
					key := strings.ToLower(strings.TrimSpace(a.Key))
					val := strings.TrimSpace(a.Val)
					switch key {
					case "name":
						name = strings.ToLower(val)
					case "property":
						prop = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				// Prefer standard description, then og:description.
				if content != "" && (name == "description" || prop == "og:description") {
					description = normalizeSpace(content)
				}
			}

		case html.EndTagToken:
			tok := z.Token()
			tag := strings.ToLower(tok.Data)
			if tag == "title" {
				inTitle = false
			}
			if depth > 0 {
				depth--
			}

		case html.TextToken:
			if inTitle && title == "" {
				title = normalizeSpace(string(z.Text()))
			}
		}

		if title != "" && description != "" {
			break
		}
	}

	return truncate(title, maxTitleLen), truncate(description, maxDescriptionLen), nil
}

func normalizeSpace(s string) string {
	return strings.Join(strings.Fields(strings.TrimSpace(s)), " ")
}

func truncate(s string, max int) string {
	if max <= 0 || len(s) <= max {
		return s
