	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}

	// Unspecified, loopback, multicast, link-local, etc.
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv4 private/reserved ranges.
	if len(ip) == net.IPv4len {
		switch {
		case ip[0] == 10:
			return true
		case ip[0] == 127:
			return true
		case ip[0] == 0:
			return true
		case ip[0] == 169 && ip[1] == 254:
			return true
		case ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31:
			return true
		case ip[0] == 192 && ip[1] == 168:
			return true
		case ip[0] >= 224:
			return true // multicast and reserved
		}
		return false
	}

	// IPv6 unique local fc00::/7, link-local fe80::/10, loopback ::1 handled above.
	if len(ip) == net.IPv6len {
		// fc00::/7
		if ip[0]&0xfe == 0xfc {
			return true
		}
		// fe80::/10
		if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
			return true
		}
	}

	return false
}

