	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protections: block localhost, link-local, private ranges, and non-IP hostnames that resolve to them.
	if err := validateNoPrivateOrLocal(parsedURL.Hostname()); err != nil {
		ctx.Error("URL host is not allowed", fasthttp.StatusBadRequest)
		return
	}

	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         requestTimeout,
		WriteTimeout:        requestTimeout,
		MaxIdleConnDuration: maxIdleConnTimeout,
		MaxConnsPerHost:     maxConnsPerHost,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", userAgent)
	freq.Header.Set("Accept", "text/html,application/xhtml+xml;q=0.9,*/*;q=0.8")

	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() < 200 || res.StatusCode() >= 300 {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	ct := strings.ToLower(string(res.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") {
		ctx.Error("Unsupported content type", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}
	if len(bodyBytes) > maxBodyBytes {
		bodyBytes = bodyBytes[:maxBodyBytes]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json; charset=utf-8")
	enc := json.NewEncoder(ctx)
	enc.SetEscapeHTML(true)
	if err := enc.Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Bound parsing to avoid extremely large inputs.
	lr := io.LimitReader(r, maxHTMLParseBytes)
	doc, err := html.Parse(lr)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
					if len(title) > maxTitleLen {
						title = title[:maxTitleLen]
					}
				}
			case "meta":
				if description == "" {
					var name, prop, content string
					for _, a := range n.Attr {
						k := strings.ToLower(a.Key)
						switch k {
						case "name":
							name = strings.ToLower(strings.TrimSpace(a.Val))
						case "property":
							prop = strings.ToLower(strings.TrimSpace(a.Val))
						case "content":
							content = strings.TrimSpace(a.Val)
						}
					}
					if content != "" && (name == "description" || prop == "og:description") {
						description = content
						if len(description) > maxDescriptionLen {
							description = description[:maxDescriptionLen]
						}
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if title != "" && description != "" {
				return
			}
			walk(c)
		}
	}

	walk(doc)

	// Normalize whitespace.
	title = strings.Join(strings.Fields(title), " ")
	description = strings.Join(strings.Fields(description), " ")
	return title, description, nil
}

func validateNoPrivateOrLocal(host string) error {
	if host == "" {
		return errors.New("empty host")
	}

	// If it's an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("disallowed ip")
		}
		return nil
	}

	// Resolve DNS and ensure none of the results are disallowed.
	ctx, cancel := context.WithTimeout(context.Background(), requestTimeout)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return err
	}
	if len(ips) == 0 {
		return errors.New("no ip records")
	}
	for _, ipa := range ips {
		if isDisallowedIP(ipa.IP) {
			return errors.New("disallowed resolved ip")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Normalize IPv4-mapped IPv6 addresses.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}

	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}

	// IPv4 private ranges + CGNAT
	if v4 := ip.To4(); v4 != nil {
		switch {
		case v4[0] == 10:
			return true
		case v4[0] == 172 && v4[1]&0xF0 == 16:
			return true
		case v4[0] == 192 && v4[1] == 168:
			return true
		case v4[0] == 127:
			return true
		case v4[0] == 169 && v4[1] == 254:
			return true
		case v4[0] == 100 && v4[1]&0xC0 == 64: // 100.64.0.0/10
			return true
		}
		return false
	}

	// IPv6 unique local (fc00::/7) and link-local (fe80::/10) and loopback (::1)
	if len(ip) == net.IPv6len {
		if ip.Equal(net.IPv6loopback) {
			return true
		}
		if ip[0]&0xFE == 0xFC { // fc00::/7
			return true
		}
		if ip[0] == 0xFE && ip[1]&0xC0 == 0x80 { // fe80::/10
			return true
		}
	}
	return false
}

