func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// IPv4
	if ip4 := ip.To4(); ip4 != nil {
		if ip4.IsLoopback() || ip4.IsLinkLocalUnicast() || ip4.IsLinkLocalMulticast() || ip4.IsMulticast() || ip4.IsUnspecified() {
			return true
		}
