		}
		// CGNAT 100.64.0.0/10
		if ip4[0] == 100 && ip4[1]&0xc0 == 64 {
			return true
		}
		// 169.254.0.0/16
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 0.0.0.0/8
		if ip4[0] == 0 {
