		}
		return false
	}

	// IPv6
	ip6 := ip.To16()
	if ip6 == nil {
		return true
	}
	// treat all non-global unicast as private/blocked
	if !ip6.IsGlobalUnicast() {
		return true
	}
	// Unique local fc00::/7
	if len(ip6) == net.IPv6len && (ip6[0]&0xfe) == 0xfc {
