	if len(ip) == net.IPv4len {
		switch {
		case ip[0] == 10:
			return false
		case ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31:
			return false
		case ip[0] == 192 && ip[1] == 168:
			return false
		case ip[0] == 127:
			return false
		case ip[0] == 169 && ip[1] == 254:
			return false
		case ip[0] == 0:
			return false
		}
