			return true
		case v4[0] == 172 && v4[1]&0xF0 == 16:
			return true
		case v4[0] == 192 && v4[1] == 168:
			return true
		case v4[0] == 127:
			return true
		case v4[0] == 169 && v4[1] == 254:
			return true
		case v4[0] == 100 && v4[1] >= 64 && v4[1] <= 127: // 100.64.0.0/10
			return true
		case v4[0] == 0:
			return true
		}
		return false
	}

	// IPv6 private/local ranges:
	// fc00::/7 (ULA), fe80::/10 (link-local), ::1 loopback handled above
	if len(ip) == net.IPv6len {
		// fc00::/7
		if ip[0]&0xFE == 0xFC {
			return true
		}
		// fe80::/10
		if ip[0] == 0xFE && (ip[1]&0xC0) == 0x80 {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if errors.Is(z.Err(), io.EOF) {
				title = strings.TrimSpace(title)
				description = strings.TrimSpace(description)
				if len(title) > maxTitleLen {
					title = title[:maxTitleLen]
				}
				if len(description) > maxDescLen {
					description = description[:maxDescLen]
				}
				return title, description, nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			tag := strings.ToLower(t.Data)

			if tag == "title" && title == "" && tt == html.StartTagToken {
				// Read text inside <title>
				if z.Next() == html.TextToken {
					title = string(z.Text())
				}
				continue
			}

			if tag == "meta" && description == "" {
				var name, property, content string
				for _, a := range t.Attr {
					key := strings.ToLower(a.Key)
					val := strings.TrimSpace(a.Val)
					switch key {
					case "name":
						name = strings.ToLower(val)
					case "property":
						property = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				if content != "" && (name == "description" || property == "og:description") {
					description = content
				}
			}

			// Early exit if we already have both.
			if title != "" && description != "" {
				title = strings.TrimSpace(title)
				description = strings.TrimSpace(description)
				if len(title) > maxTitleLen {
					title = title[:maxTitleLen]
				}
				if len(description) > maxDescLen {
					description = description[:maxDescLen]
				}
				return title, description, nil
			}
		}
	}
}

