// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := goquery.NewDocumentFromReader(r)
	if err != nil {
		return "", "", err
	}

	title = strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description
	if v, ok := doc.Find(`meta[name="description"]`).First().Attr("content"); ok {
		description = strings.TrimSpace(v)
	}

	// Fallbacks commonly used by sites
	if description == "" {
		if v, ok := doc.Find(`meta[property="og:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}
	if description == "" {
		if v, ok := doc.Find(`meta[name="twitter:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}

	return title, description, nil
}

// validateNoPrivateNetwork rejects URLs that resolve to private/loopback/link-local/etc.
func validateNoPrivateNetwork(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return fmt.Errorf("Invalid URL host")
	}

	// Block obvious localhost names immediately.
	switch strings.ToLower(host) {
	case "localhost", "localhost.localdomain":
		return fmt.Errorf("URL host is not allowed")
	}

	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return fmt.Errorf("Failed to resolve host")
	}

	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return fmt.Errorf("URL host is not allowed")
		}
	}
	return nil
}

// normalizeIP converts IPv4-mapped IPv6 to IPv4 and returns a canonical 16-byte form for IPv6.
func normalizeIP(ip net.IP) net.IP {
	if ip == nil {
		return nil
	}
	// Convert IPv4-mapped IPv6 to 4-byte IPv4.
	if ip4 := ip.To4(); ip4 != nil {
		return ip4
	}
	// Ensure 16-byte representation for IPv6.
	if ip16 := ip.To16(); ip16 != nil {
		return ip16
	}
	return ip
}

func isDisallowedIP(ip net.IP) bool {
	ip = normalizeIP(ip)
	if ip == nil {
		return true
	}

	// Loopback, unspecified, multicast, link-local, etc.
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges.
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1]&0xF0 == 16 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip4[0] == 100 && (ip4[1]&0xC0) == 64 {
			return true
		}
		// 192.0.0.0/24
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 0 {
			return true
		}
		// 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (TEST-NET)
		if (ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 2) ||
			(ip4[0] == 198 && ip4[1] == 51 && ip4[2] == 100) ||
			(ip4[0] == 203 && ip4[1] == 0 && ip4[2] == 113) {
			return true
		}
		// 198.18.0.0/15 (benchmarking)
		if ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19) {
			return true
		}
		return false
	}

	// IPv6 checks.
	// Unique local: fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xFE) == 0xFC {
		return true
	}
	// Link-local: fe80::/10
	if len(ip) == net.IPv6len && ip[0] == 0xFE && (ip[1]&0xC0) == 0x80 {
		return true
	}
	// Documentation prefix: 2001:db8::/32
	if len(ip) == net.IPv6len && ip[0] == 0x20 && ip[1] == 0x01 && ip[2] == 0x0d && ip[3] == 0xb8 {
		return true
	}

	return false
}

// safeDialer returns a dial function that blocks private/loopback/etc. IPs even if DNS changes.
func safeDialer(timeout time.Duration) fasthttp.DialFunc {
	var d net.Dialer
	d.Timeout = timeout
	return func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		ips, err := net.LookupIP(host)
		if err != nil || len(ips) == 0 {
			return nil, fmt.Errorf("failed to resolve host")
		}
		for _, ip := range ips {
			if isDisallowedIP(ip) {
				return nil, fmt.Errorf("dial to disallowed IP")
			}
		}

		// Dial using the original host:port (keeps SNI/Host semantics for TLS in fasthttp).
		return d.Dial("tcp", net.JoinHostPort(host, port))
	}
}

