	if !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") && ct != "" {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, previewResp{URL: req.URL, Error: "content is not html"})
		return
