	// fasthttp.Response doesn't expose the final URL after redirects.
	// Return the originally requested URL as FinalURL.
	finalURL := req.URL

	writeJSON(ctx, fasthttp.StatusOK, previewResp{
		URL:         req.URL,
		FinalURL:    finalURL,
		Title:       title,
		Description: desc,
	})
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetContentType("application/json; charset=utf-8")
			_, _ = ctx.WriteString(`{"error":"not found"}` + "\n")
		}
	}

	addr := ":8080"
	log.Printf("listening on %s (POST /preview)", addr)
	if err := fasthttp.ListenAndServe(addr, h); err != nil {
		log.Fatal(err)
	}
}

