	finalURI := string(res.Header.Peek("Location"))
	// Note: fasthttp doesn't expose final URL directly; DoRedirects updates RequestURI in req.
	// We'll validate the request's current URI.
	finalURL := string(freq.URI().FullURI())
	if finalURL != "" {
