				writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{Error: "Redirected URL host is not allowed"})
				return
			}
		}
	}
	_ = finalURI

	if res.StatusCode() < 200 || res.StatusCode() >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", res.StatusCode())})
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{Error: "Empty response body"})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusInternalServerError, PreviewResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, v any) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	b, err := json.Marshal(v)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
	ctx.SetBody(b)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := goquery.NewDocumentFromReader(r)
	if err != nil {
		return "", "", err
	}

	title = strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description
	if v, ok := doc.Find(`meta[name="description"]`).First().Attr("content"); ok {
		description = strings.TrimSpace(v)
	}

	// Fallbacks (common social tags)
	if description == "" {
		if v, ok := doc.Find(`meta[property="og:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}
	if title == "" {
		if v, ok := doc.Find(`meta[property="og:title"]`).First().Attr("content"); ok {
			title = strings.TrimSpace(v)
		}
	}

	return title, description, nil
}

func isBlockedHost(host string) bool {
	h := strings.TrimSpace(strings.ToLower(host))
	h = strings.TrimSuffix(h, ".")
	if h == "" {
		return true
	}

	// Block obvious local names
	if h == "localhost" || h == "localhost.localdomain" {
		return true
	}

	// If it's an IP literal, validate directly
	if ip := net.ParseIP(h); ip != nil {
		return isBlockedIP(ip)
	}

	// Resolve DNS and block if any resolved IP is disallowed.
	ips, err := net.LookupIP(h)
	if err != nil || len(ips) == 0 {
		// If we can't resolve, treat as invalid/untrusted for this previewer
		return true
	}
	for _, ip := range ips {
		if isBlockedIP(ip) {
			return true
		}
	}
	return false
}

func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	ip4 := ip.To4()
	if ip4 != nil {
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return true
		}
		// 192.0.0.0/24
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 0 {
			return true
		}
		// 198.18.0.0/15 (benchmarking)
		if ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19) {
			return true
		}
		// Multicast 224.0.0.0/4 and reserved 240.0.0.0/4
		if ip4[0] >= 224 {
			return true
		}
		return false
	}

	// IPv6 checks
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Unique local addresses fc00::/7
	if len(ip) == net.IPv6len {
		if (ip[0] & 0xfe) == 0xfc {
			return true
		}
		// Multicast ff00::/8
		if ip[0] == 0xff {
			return true
		}
		// Unspecified ::
		if ip.IsUnspecified() {
			return true
		}
	}
	return false
}

func main() {
	// Example server wiring (optional for compilation/run):
	// fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

