	dec := json.NewDecoder(bytes.NewReader(body))
	dec.DisallowUnknownFields()
	if err := dec.Decode(&req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL == nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.User != nil {
		ctx.Error("URL must not contain user info", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Hostname() == "" {
		ctx.Error("URL must include a host", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: block localhost, private, link-local, multicast, etc.
	if err := validateTargetHost(parsedURL.Hostname()); err != nil {
		ctx.Error("URL host is not allowed", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeouts and safe dialer.
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// addr is host:port after DNS resolution decision by fasthttp.
			// We still validate the host part here to prevent bypasses.
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				host = addr
			}
			if err := validateTargetHost(host); err != nil {
				return nil, errBlockedHost
			}
			d := &net.Dialer{Timeout: 5 * time.Second}
			return d.Dial("tcp", addr)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml;q=0.9,*/*;q=0.1")

	// fasthttp doesn't provide a simple streaming limit API for DoRedirects.
	// We'll enforce a size limit after the fact and also use a short timeout.
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		if errors.Is(err, errBlockedHost) {
			ctx.Error("URL host is not allowed", fasthttp.StatusBadRequest)
