// validateTargetHost blocks SSRF to local/private networks.
// It resolves DNS and checks all returned IPs.
func validateTargetHost(host string) error {
	h := strings.TrimSpace(strings.TrimSuffix(host, "."))
	if h == "" {
		return errBlockedHost
	}

	// Block obvious local names.
	lh := strings.ToLower(h)
	if lh == "localhost" || strings.HasSuffix(lh, ".localhost") {
		return errBlockedHost
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(h); ip != nil {
		if isBlockedIP(ip) {
			return errBlockedHost
		}
		return nil
	}

	// Resolve and validate all A/AAAA records.
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, h)
	if err != nil || len(ips) == 0 {
		return errBlockedHost
	}
	for _, ipa := range ips {
		if isBlockedIP(ipa.IP) {
			return errBlockedHost
		}
	}
	return nil
}

func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}

	// Unspecified, loopback, multicast, link-local.
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges + CGNAT + benchmark + documentation ranges.
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1]&0xF0 == 16 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local v4)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip4[0] == 100 && (ip4[1]&0xC0) == 64 {
			return true
		}
		// 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (TEST-NET)
		if (ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 2) ||
			(ip4[0] == 198 && ip4[1] == 51 && ip4[2] == 100) ||
			(ip4[0] == 203 && ip4[1] == 0 && ip4[2] == 113) {
			return true
		}
		// 198.18.0.0/15 (benchmarking)
		if ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19) {
			return true
		}
		return false
	}

	// IPv6 checks.
	if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
		return true
	}
	// Unique local addresses fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xFE) == 0xFC {
		return true
	}
	// Documentation 2001:db8::/32
	if len(ip) == net.IPv6len && ip[0] == 0x20 && ip[1] == 0x01 && ip[2] == 0x0d && ip[3] == 0xb8 {
		return true
	}
	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}
		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
					if len(title) > maxTitleLen {
						title = title[:maxTitleLen]
					}
				}
			case "meta":
				if description == "" {
					var name, prop, content string
					for _, a := range n.Attr {
						switch strings.ToLower(a.Key) {
						case "name":
							name = strings.ToLower(strings.TrimSpace(a.Val))
						case "property":
							prop = strings.ToLower(strings.TrimSpace(a.Val))
						case "content":
							content = strings.TrimSpace(a.Val)
						}
					}
					if content != "" && (name == "description" || prop == "og:description") {
						description = content
						if len(description) > maxDescLen {
							description = description[:maxDescLen]
						}
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}
	walk(doc)

	return title, description, nil
}

func main() {}

