	if u.Host == "" {
		return "", errors.New("invalid url host")
	}
	return u.String(), nil
}

func extractTitleAndDescription(htmlBytes []byte) (title, desc string) {
	lower := bytes.ToLower(htmlBytes)

	if i := bytes.Index(lower, []byte("<title")); i >= 0 {
		gt := bytes.IndexByte(lower[i:], '>')
		if gt >= 0 {
			start := i + gt + 1
			if end := bytes.Index(lower[start:], []byte("</title>")); end >= 0 {
				raw := string(htmlBytes[start : start+end])
				raw = strings.TrimSpace(stripTags(raw))
				title = html.UnescapeString(raw)
			}
		}
	}

	desc = extractMetaContent(lower, htmlBytes, "name", "description")
	if desc == "" {
		desc = extractMetaContent(lower, htmlBytes, "property", "og:description")
	}
	if desc == "" {
		desc = extractMetaContent(lower, htmlBytes, "name", "og:description")
	}
	desc = html.UnescapeString(strings.TrimSpace(desc))
	return
}

func extractMetaContent(lower, original []byte, attrKey, attrVal string) string {
	pos := 0
	for {
		i := bytes.Index(lower[pos:], []byte("<meta"))
		if i < 0 {
			return ""
		}
		i += pos
		j := bytes.IndexByte(lower[i:], '>')
		if j < 0 {
			return ""
		}
		j += i
		tagLower := lower[i : j+1]
		tagOrig := original[i : j+1]

		if hasAttr(tagLower, attrKey, attrVal) {
			if c := getAttrValue(tagOrig, "content"); c != "" {
				return c
			}
		}
		pos = j + 1
	}
}

func hasAttr(tagLower []byte, key, val string) bool {
	keyEq := []byte(strings.ToLower(key) + "=")
	idx := bytes.Index(tagLower, keyEq)
	for idx >= 0 {
		rest := bytes.TrimSpace(tagLower[idx+len(keyEq):])
		if len(rest) == 0 {
			return false
		}
		v := ""
		switch rest[0] {
		case '"', '\'':
			q := rest[0]
			end := bytes.IndexByte(rest[1:], q)
			if end < 0 {
				return false
			}
			v = string(rest[1 : 1+end])
		default:
			end := 0
			for end < len(rest) && rest[end] != ' ' && rest[end] != '\t' && rest[end] != '\n' && rest[end] != '\r' && rest[end] != '>' {
				end++
			}
			v = string(rest[:end])
		}
		if strings.EqualFold(v, val) {
			return true
		}
		next := bytes.Index(tagLower[idx+len(keyEq):], keyEq)
		if next < 0 {
			return false
		}
		idx = idx + len(keyEq) + next
	}
	return false
}

func getAttrValue(tagOrig []byte, key string) string {
	lower := bytes.ToLower(tagOrig)
	keyEq := []byte(strings.ToLower(key) + "=")
	idx := bytes.Index(lower, keyEq)
	for idx >= 0 {
		restOrig := bytes.TrimSpace(tagOrig[idx+len(keyEq):])
		if len(restOrig) == 0 {
			return ""
		}
		switch restOrig[0] {
		case '"', '\'':
			q := restOrig[0]
			end := bytes.IndexByte(restOrig[1:], q)
			if end < 0 {
				return ""
			}
			return string(restOrig[1 : 1+end])
		default:
			end := 0
			for end < len(restOrig) && restOrig[end] != ' ' && restOrig[end] != '\t' && restOrig[end] != '\n' && restOrig[end] != '\r' && restOrig[end] != '>' {
				end++
			}
			return string(restOrig[:end])
		}
	}
	return ""
}

func stripTags(s string) string {
	var b strings.Builder
	b.Grow(len(s))
	inTag := false
	for _, r := range s {
		switch r {
		case '<':
			inTag = true
		case '>':
			inTag = false
		default:
			if !inTag {
				b.WriteRune(r)
			}
		}
	}
	return b.String()
}

// doRedirectsTimeout performs the request following up to maxRedirects redirects within the given timeout.
// It updates req to the final URL and fills resp with the final response.
func doRedirectsTimeout(client *fasthttp.Client, req *fasthttp.Request, resp *fasthttp.Response, maxRedirects int, timeout time.Duration) error {
	deadline := time.Now().Add(timeout)

	for redirects := 0; ; redirects++ {
		remaining := time.Until(deadline)
		if remaining <= 0 {
			return fasthttp.ErrTimeout
		}

		resp.Reset()
		if err := client.DoTimeout(req, resp, remaining); err != nil {
			return err
		}

		status := resp.StatusCode()
		if status != fasthttp.StatusMovedPermanently &&
			status != fasthttp.StatusFound &&
			status != fasthttp.StatusSeeOther &&
			status != fasthttp.StatusTemporaryRedirect &&
			status != fasthttp.StatusPermanentRedirect {
			return nil
		}

		if redirects >= maxRedirects {
			return errors.New("too many redirects")
		}

		loc := string(resp.Header.Peek("Location"))
		loc = strings.TrimSpace(loc)
		if loc == "" {
			return errors.New("redirect location is empty")
		}

		cur, err := url.Parse(string(req.URI().FullURI()))
		if err != nil {
			return err
		}
		next, err := url.Parse(loc)
		if err != nil {
			return err
		}
		next = cur.ResolveReference(next)
		if next.Scheme != "http" && next.Scheme != "https" {
			return errors.New("unsupported redirect scheme")
		}
		if next.Host == "" {
			return errors.New("invalid redirect host")
		}

		// Per RFC, 303 should switch to GET. Commonly 301/302 also switch POST->GET, but we only send GET anyway.
		req.Header.SetMethod(fasthttp.MethodGet)
		req.SetRequestURI(next.String())
	}
}

// FetchURLPreview receives POST JSON {"url":"..."} and returns {"url","final_url","title","description"}.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		return
	}

	var reqBody fetchURLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		badRequest(ctx, "invalid json body")
		return
	}

	rawURL, err := normalizeURL(reqBody.URL)
	if err != nil {
		badRequest(ctx, err.Error())
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.Header.SetMethod(fasthttp.MethodGet)
	req.SetRequestURI(rawURL)
	req.Header.SetUserAgent("url-preview-bot/1.0")
	req.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Timeout must be 3 seconds.
	timeout := 3 * time.Second

	// Must use DoRedirects to fetch the provided URL.
	if err := doRedirectsTimeout(client, req, resp, 10, timeout); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchURLPreviewResponse{
			URL:   rawURL,
			Error: "fetch failed: " + err.Error(),
		})
		return
	}

	status := resp.StatusCode()
	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchURLPreviewResponse{
			URL:   rawURL,
			Error: "upstream returned status " + fasthttp.StatusMessage(status),
		})
		return
	}

	ct := strings.ToLower(string(resp.Header.ContentType()))
	if !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml") && ct != "" {
		writeJSON(ctx, fasthttp.StatusOK, fetchURLPreviewResponse{
			URL:      rawURL,
			FinalURL: string(req.URI().FullURI()),
			Error:    "content is not html",
		})
		return
	}

	body := resp.Body()
	title, desc := extractTitleAndDescription(body)

	writeJSON(ctx, fasthttp.StatusOK, fetchURLPreviewResponse{
		URL:         rawURL,
		FinalURL:    string(req.URI().FullURI()),
		Title:       title,
		Description: desc,
	})
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
		}
	}

	addr := ":8080"
	log.Printf("listening on %s (POST /preview)", addr)
	if err := fasthttp.ListenAndServe(addr, h); err != nil {
		log.Fatal(err)
	}
}

