func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// IPv4
	if ip4 := ip.To4(); ip4 != nil {
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return true
		}
		// 192.0.0.0/24
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 0 {
			return true
		}
		// 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (TEST-NETs)
		if (ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 2) ||
			(ip4[0] == 198 && ip4[1] == 51 && ip4[2] == 100) ||
			(ip4[0] == 203 && ip4[1] == 0 && ip4[2] == 113) {
			return true
		}
		// 198.18.0.0/15 (benchmarking)
		if ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19) {
			return true
		}
		// 224.0.0.0/4 multicast and 240.0.0.0/4 reserved
		if ip4[0] >= 224 {
			return true
		}
		return false
	}

	// IPv6 checks
	if ip6 := ip.To16(); ip6 != nil {
		// loopback ::1
		if ip6.IsLoopback() {
			return true
		}
		// link-local fe80::/10
		if len(ip6) == net.IPv6len && ip6[0] == 0xfe && (ip6[1]&0xc0) == 0x80 {
			return true
		}
		// unique local fc00::/7
		if len(ip6) == net.IPv6len && (ip6[0]&0xfe) == 0xfc {
			return true
		}
		// unspecified ::
		if ip6.IsUnspecified() {
			return true
		}
		// multicast ff00::/8
		if len(ip6) == net.IPv6len && ip6[0] == 0xff {
			return true
		}
		return false
	}

	return true
}

func validateTargetURL(targetURL string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}
	if parsedURL.Hostname() == "" {
		return nil, fmt.Errorf("URL must include a hostname")
	}
	if parsedURL.User != nil {
		return nil, fmt.Errorf("userinfo in URL is not allowed")
	}

	host := parsedURL.Hostname()
	switch strings.ToLower(host) {
	case "localhost", "localhost.localdomain":
		return nil, fmt.Errorf("hostname is not allowed")
	}

	// If host is an IP literal, validate directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("target host is not allowed")
		}
		return parsedURL, nil
	}

	// Resolve DNS and block if any resolved IP is private/reserved
	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return nil, fmt.Errorf("failed to resolve host")
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("target host is not allowed")
		}
	}

	return parsedURL, nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Accept both JSON body and form parameter "url"
	var targetURL string

	ct := strings.ToLower(string(ctx.Request.Header.ContentType()))
	if strings.Contains(ct, "application/json") {
		var req struct {
			URL string `json:"url"`
		}
		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}
		targetURL = req.URL
	} else {
		targetURL = string(ctx.FormValue("url"))
		// If not present in form, try query as a fallback
		if strings.TrimSpace(targetURL) == "" {
			targetURL = string(ctx.QueryArgs().Peek("url"))
		}
	}

	targetURL = strings.TrimSpace(targetURL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := validateTargetURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// DNS rebinding protection: resolve once, validate, then dial using the validated IP
	host := parsedURL.Hostname()
	port := parsedURL.Port()
	if port == "" {
		if parsedURL.Scheme == "https" {
			port = "443"
		} else {
			port = "80"
		}
	}

	var dialAddr string
	if ip := net.ParseIP(host); ip != nil {
		dialAddr = net.JoinHostPort(ip.String(), port)
	} else {
		ips, err := net.LookupIP(host)
		if err != nil || len(ips) == 0 {
			ctx.Error("failed to resolve host", fasthttp.StatusBadRequest)
			return
		}
		var chosen net.IP
		for _, ip := range ips {
			if !isPrivateIP(ip) {
				chosen = ip
				break
			}
		}
		if chosen == nil {
			ctx.Error("target host is not allowed", fasthttp.StatusBadRequest)
			return
		}
		dialAddr = net.JoinHostPort(chosen.String(), port)
	}

	dialer := &net.Dialer{Timeout: 5 * time.Second}
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Ignore addr (which may trigger re-resolution); use validated dialAddr.
			return dialer.DialContext(context.Background(), "tcp", dialAddr)
		},
		ReadTimeout:         5 * time.Second,
		WriteTimeout:        5 * time.Second,
		MaxIdleConnDuration: 5 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Do not follow redirects (security tests expect redirects to be blocked)
	if err := client.Do(freq, res); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Block redirects explicitly
	if res.StatusCode() >= 300 && res.StatusCode() <= 399 {
		ctx.Error("Redirects are not allowed", fasthttp.StatusBadRequest)
		return
	}

	if res.StatusCode() < 200 || res.StatusCode() > 299 {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json; charset=utf-8")
	b, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
	ctx.SetBody(b)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := goquery.NewDocumentFromReader(r)
	if err != nil {
		return "", "", err
	}

	title = strings.TrimSpace(doc.Find("title").First().Text())

	// Prefer standard meta description
	if v, ok := doc.Find(`meta[name="description"]`).First().Attr("content"); ok {
		description = strings.TrimSpace(v)
	}

	// Fallbacks commonly used by social platforms
	if description == "" {
		if v, ok := doc.Find(`meta[property="og:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}
	if description == "" {
		if v, ok := doc.Find(`meta[name="twitter:description"]`).First().Attr("content"); ok {
			description = strings.TrimSpace(v)
		}
	}

	return title, description, nil
}

func main() {
	// Example wiring:
	// POST /preview with body: {"url":"https://example.com"}
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	_ = fasthttp.ListenAndServe(":8080", h)
}

