// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const (
	maxRequestBodyBytes  = 8 * 1024
	maxResponseBodyBytes = 2 * 1024 * 1024
	maxTitleLen          = 256
	maxDescLen           = 512
	maxRedirects         = 5
)

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	if len(ctx.PostBody()) > maxRequestBodyBytes {
		ctx.Error("Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.Parse(targetURL)
	if err != nil || parsedURL == nil || parsedURL.Host == "" {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.User != nil {
		ctx.Error("URL must not contain credentials", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: block localhost/private/link-local/multicast/unspecified and common local hostnames.
	if err := validateNoPrivateOrLocalhost(parsedURL); err != nil {
		ctx.Error("URL not allowed", fasthttp.StatusBadRequest)
		return
	}

	client := &fasthttp.Client{
		// DialDualStack uses net.Dialer under the hood; we additionally validate resolved IPs above.
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml;q=0.9,*/*;q=0.1")

	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() < 200 || res.StatusCode() >= 300 {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Enforce response size limit.
	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}
	if len(bodyBytes) > maxResponseBodyBytes {
		ctx.Error("Response body too large", fasthttp.StatusBadGateway)
		return
	}

	// Basic content-type check (allow missing/unknown but prefer HTML).
	ct := strings.ToLower(string(res.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") {
		ctx.Error("Unsupported content type", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error("Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json; charset=utf-8")
	enc := json.NewEncoder(ctx)
	enc.SetEscapeHTML(true)
	if err := enc.Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

func validateNoPrivateOrLocalhost(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return errors.New("empty hostname")
	}

	lh := strings.ToLower(strings.TrimSuffix(host, "."))
	switch lh {
	case "localhost", "localhost.localdomain":
		return errors.New("localhost not allowed")
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(lh); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("ip not allowed")
		}
		return nil
	}

	// Resolve DNS and validate all A/AAAA records.
	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return errors.New("dns lookup failed")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return errors.New("resolved ip not allowed")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Normalize IPv4-mapped IPv6 addresses to IPv4.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}

	// Unspecified / loopback.
	if ip.IsUnspecified() || ip.IsLoopback() {
		return true
	}

	// Link-local, multicast.
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
		return true
	}

	// Private ranges (IPv4).
	if len(ip) == net.IPv4len {
		switch {
		case ip[0] == 10:
			return true
		case ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31:
			return true
		case ip[0] == 192 && ip[1] == 168:
			return true
		case ip[0] == 127:
			return true
		case ip[0] == 169 && ip[1] == 254: // link-local
			return true
		case ip[0] == 100 && ip[1] >= 64 && ip[1] <= 127: // CGNAT
			return true
		case ip[0] == 0:
			return true
		}
		return false
	}

	// IPv6 unique-local (fc00::/7).
	if len(ip) == net.IPv6len {
		if ip[0]&0xfe == 0xfc {
			return true
		}
		// ::1 already covered by IsLoopback above, but keep explicit for clarity.
		if ip.IsLoopback() {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	var inTitle bool
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			tag := strings.ToLower(t.Data)

			if tag == "title" && tt == html.StartTagToken {
				inTitle = true
				continue
			}

			if tag == "meta" {
				var name, prop, content string
				for _, a := range t.Attr {
					k := strings.ToLower(a.Key)
					switch k {
					case "name":
						name = strings.ToLower(strings.TrimSpace(a.Val))
					case "property":
						prop = strings.ToLower(strings.TrimSpace(a.Val))
					case "content":
						content = strings.TrimSpace(a.Val)
					}
				}

				// Prefer standard description; fall back to og:description if description not set.
				if description == "" && name == "description" && content != "" {
					description = truncateClean(content, maxDescLen)
				} else if description == "" && prop == "og:description" && content != "" {
					description = truncateClean(content, maxDescLen)
				}
			}

		case html.EndTagToken:
			t := z.Token()
			if strings.ToLower(t.Data) == "title" {
				inTitle = false
			}

		case html.TextToken:
			if inTitle && title == "" {
				title = truncateClean(string(z.Text()), maxTitleLen)
			}
		}
	}
}

func truncateClean(s string, max int) string {
	s = strings.TrimSpace(strings.Join(strings.Fields(s), " "))
	if max <= 0 || len(s) <= max {
		return s
	}
	rs := []rune(s)
	if len(rs) <= max {
		return s
	}
	return string(rs[:max])
}

func main() {
	// Example wiring (not required by task, but keeps file runnable).
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}
	_ = fasthttp.ListenAndServe(":8080", h)
}

