	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResp{
			URL:   target,
			Error: fmt.Sprintf("upstream returned status %d", status),
		})
		return
	}

	ct := strings.ToLower(string(fresp.Header.ContentType()))
	if !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, fetchResp{
			URL:   target,
			Error: "upstream content is not html",
		})
