// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, prop, content string
				for _, a := range n.Attr {
					key := strings.ToLower(a.Key)
					switch key {
					case "name":
						name = strings.ToLower(strings.TrimSpace(a.Val))
					case "property":
						prop = strings.ToLower(strings.TrimSpace(a.Val))
					case "content":
						content = strings.TrimSpace(a.Val)
					}
				}
				if description == "" && content != "" {
					if name == "description" || prop == "og:description" {
						description = content
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description, nil
}

func validateNoSSRF(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return fmt.Errorf("Invalid URL host")
	}

	// Disallow obvious localhost names
	h := strings.ToLower(strings.TrimSpace(host))
	if h == "localhost" || h == "localhost." {
		return fmt.Errorf("URL host is not allowed")
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(h); ip != nil {
		if isDisallowedIP(ip) {
			return fmt.Errorf("URL host is not allowed")
		}
		return nil
	}

	// Resolve DNS and ensure all A/AAAA are public.
	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return fmt.Errorf("Unable to resolve host")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return fmt.Errorf("URL host is not allowed")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Normalize IPv4-mapped IPv6 to IPv4 where applicable.
	if ip4 := ip.To4(); ip4 != nil {
		ip = ip4
	} else {
		ip = ip.To16()
		if ip == nil {
			return true
		}
	}

	// Unspecified, loopback, multicast, link-local
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges (IPv4)
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return true
		case ip4[0] == 127:
			return true
		case ip4[0] == 169 && ip4[1] == 254:
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		case ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127: // CGNAT
			return true
		case ip4[0] == 0:
			return true
		}
		return false
	}

	// IPv6 private/ULA and other special ranges
	// fc00::/7 (ULA)
	if len(ip) == net.IPv6len && (ip[0]&0xfe) == 0xfc {
		return true
	}
	// fe80::/10 (link-local) already covered by IsLinkLocalUnicast, but keep explicit
	if len(ip) == net.IPv6len && ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
		return true
	}

	return false
}

func safeDialer(timeout time.Duration) func(addr string) (net.Conn, error) {
	d := &net.Dialer{Timeout: timeout}
	return func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			// Fallback: if no port, still attempt but validate host
			host = addr
			port = ""
		}

		if ip := net.ParseIP(host); ip != nil {
			if isDisallowedIP(ip) {
				return nil, fmt.Errorf("blocked address")
			}
		} else {
			ips, err := net.LookupIP(host)
			if err != nil || len(ips) == 0 {
				return nil, fmt.Errorf("dns lookup failed")
			}
			for _, ip := range ips {
				if isDisallowedIP(ip) {
					return nil, fmt.Errorf("blocked address")
				}
			}
		}

		if port == "" {
			return d.Dial("tcp", addr)
		}
		return d.Dial("tcp", net.JoinHostPort(host, port))
	}
}

func main() {
	// Minimal server wiring for completeness.
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	_ = fasthttp.ListenAndServe(":8080", h)
}

