	// Disallow userinfo (prevents leaking credentials, reduces SSRF tricks).
	if parsed.User != nil {
		ctx.Error("URL must not contain userinfo", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: block private/loopback/link-local/multicast/etc.
	if err := validateNoPrivateNetwork(parsed); err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Use a context not tied to fasthttp.RequestCtx (it isn't a context.Context and can panic).
	lookupCtx, cancel := context.WithTimeout(context.Background(), fetchTimeout)
	defer cancel()

	client := &fasthttp.Client{
		// Use a safe dialer that blocks private/loopback IPs even after DNS resolution.
		Dial: func(addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			ips, err := net.DefaultResolver.LookupIPAddr(lookupCtx, host)
			if err != nil {
				return nil, err
			}
			if len(ips) == 0 {
				return nil, errors.New("no IPs for host")
			}
			for _, ip := range ips {
				if isDisallowedIP(ip.IP) {
					return nil, errors.New("blocked destination address")
				}
			}

			dialer := &net.Dialer{Timeout: fetchTimeout}
			return dialer.Dial("tcp", net.JoinHostPort(host, port))
		},
		ReadTimeout:                   fetchTimeout,
		WriteTimeout:                  fetchTimeout,
		MaxIdleConnDuration:           10 * time.Second,
		MaxConnsPerHost:               4,
		DisableHeaderNamesNormalizing: true,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsed.String())
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", userAgent)
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Fetch with redirects but keep SSRF protections on each redirect.
	if err := doSafeRedirects(client, freq, res, maxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() < 200 || res.StatusCode() > 299 {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Basic content-type gate (still parse if missing, but reject obvious non-HTML).
	ct := strings.ToLower(string(res.Header.ContentType()))
	if ct != "" && !strings.HasPrefix(ct, contentTypeHTMLPref) && !strings.Contains(ct, "html") {
		ctx.Error("Unsupported content type", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}
	if len(bodyBytes) > maxHTMLBytes {
		bodyBytes = bodyBytes[:maxHTMLBytes]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType(contentTypeJSON)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// doSafeRedirects performs GET requests following redirects while validating each redirect URL.
func doSafeRedirects(client *fasthttp.Client, req *fasthttp.Request, resp *fasthttp.Response, max int) error {
	curURL := string(req.URI().FullURI())
	for i := 0; i <= max; i++ {
		req.URI().Update(curURL)
		if err := client.Do(req, resp); err != nil {
			return err
		}

		code := resp.StatusCode()
		if code == fasthttp.StatusMovedPermanently ||
			code == fasthttp.StatusFound ||
			code == fasthttp.StatusSeeOther ||
			code == fasthttp.StatusTemporaryRedirect ||
			code == fasthttp.StatusPermanentRedirect {

			loc := string(resp.Header.Peek("Location"))
			if loc == "" {
				return errors.New("redirect without Location header")
			}

			base, err := url.Parse(curURL)
			if err != nil {
				return err
			}
			next, err := url.Parse(loc)
			if err != nil {
				return err
			}
			next = base.ResolveReference(next)

			if next.Scheme != "http" && next.Scheme != "https" {
				return errors.New("redirect to unsupported scheme")
			}
			if next.User != nil {
				return errors.New("redirect URL contains userinfo")
			}
			if err := validateNoPrivateNetwork(next); err != nil {
				return err
			}

			// Clear response before next iteration.
			resp.Reset()
			curURL = next.String()
			continue
		}

		// Not a redirect, done.
		return nil
	}
	return errors.New("too many redirects")
}

// validateNoPrivateNetwork blocks URLs pointing to private/loopback/link-local/etc.
// It checks hostname/IP literals; DNS resolution is enforced again in the Dial function.
func validateNoPrivateNetwork(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return errors.New("invalid host")
	}

	// If it's an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("destination address is not allowed")
		}
		return nil
	}

	// Block obvious local hostnames.
	h := strings.ToLower(host)
	if h == "localhost" || strings.HasSuffix(h, ".localhost") {
		return errors.New("destination host is not allowed")
	}

	return nil
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize to 16-byte representation for checks.
	ip = ip.To16()
	if ip == nil {
		return true
	}

	// Loopback, unspecified, multicast.
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}

	// Link-local unicast/multicast.
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges (IPv4 + IPv6 ULA) and other special ranges.
	if isPrivateIPv4(ip) || isCarrierGradeNAT(ip) || isBenchmarking(ip) || isDocumentation(ip) || isIPv6ULA(ip) {
		return true
	}

	return false
}

func isPrivateIPv4(ip net.IP) bool {
	ip4 := ip.To4()
	if ip4 == nil {
		return false
	}
	// 10.0.0.0/8
	if ip4[0] == 10 {
		return true
	}
	// 172.16.0.0/12
	if ip4[0] == 172 && ip4[1]&0xF0 == 16 {
		return true
	}
	// 192.168.0.0/16
	if ip4[0] == 192 && ip4[1] == 168 {
		return true
	}
	// 127.0.0.0/8 loopback handled by IsLoopback, but keep explicit.
	if ip4[0] == 127 {
		return true
	}
	// 169.254.0.0/16 link-local handled by IsLinkLocalUnicast, but keep explicit.
	if ip4[0] == 169 && ip4[1] == 254 {
		return true
	}
	return false
}

func isCarrierGradeNAT(ip net.IP) bool {
	ip4 := ip.To4()
	if ip4 == nil {
		return false
	}
	// 100.64.0.0/10
	return ip4[0] == 100 && (ip4[1]&0xC0) == 64
}

func isBenchmarking(ip net.IP) bool {
	ip4 := ip.To4()
	if ip4 == nil {
		return false
	}
	// 198.18.0.0/15
	return ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19)
}

func isDocumentation(ip net.IP) bool {
	ip4 := ip.To4()
	if ip4 == nil {
		return false
	}
	// 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24
	if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 2 {
		return true
	}
	if ip4[0] == 198 && ip4[1] == 51 && ip4[2] == 100 {
		return true
	}
	if ip4[0] == 203 && ip4[1] == 0 && ip4[2] == 113 {
		return true
	}
	return false
}

func isIPv6ULA(ip net.IP) bool {
	// fc00::/7
	return ip[0]&0xFE == 0xFC
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil {
			return
		}
		if title == "" && n.Type == html.ElementNode && strings.EqualFold(n.Data, "title") {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
				if len(title) > maxTitleLen {
					title = title[:maxTitleLen]
				}
			}
		}

		if description == "" && n.Type == html.ElementNode && strings.EqualFold(n.Data, "meta") {
			var name, property, content string
			for _, a := range n.Attr {
				switch strings.ToLower(a.Key) {
				case "name":
					name = strings.ToLower(strings.TrimSpace(a.Val))
				case "property":
					property = strings.ToLower(strings.TrimSpace(a.Val))
				case "content":
					content = strings.TrimSpace(a.Val)
				}
			}
			if content != "" && (name == "description" || property == "og:description") {
				description = content
				if len(description) > maxDescriptionLen {
					description = description[:maxDescriptionLen]
				}
			}
		}

		// Stop early if we have both.
		if title != "" && description != "" {
			return
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}
	walk(doc)

	return title, description, nil
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	_ = fasthttp.ListenAndServe(":8080", h)
}

