	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	seenTokens := 0

	var inTitle bool
	for {
		tt := z.Next()
		seenTokens++
		if seenTokens > maxHTMLParseTokens {
			return strings.TrimSpace(title), strings.TrimSpace(description), nil
		}

		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			name := strings.ToLower(t.Data)

			if name == "title" && tt == html.StartTagToken {
				inTitle = true
				continue
			}

			if name == "meta" {
				var metaName, metaProp, metaContent string
				for _, a := range t.Attr {
					k := strings.ToLower(a.Key)
					switch k {
					case "name":
						metaName = strings.ToLower(strings.TrimSpace(a.Val))
					case "property":
						metaProp = strings.ToLower(strings.TrimSpace(a.Val))
					case "content":
						metaContent = strings.TrimSpace(a.Val)
					}
				}

				// Prefer standard meta description; fallback to og:description if empty.
				if description == "" && metaName == "description" && metaContent != "" {
					description = truncate(metaContent, maxDescriptionLen)
				} else if description == "" && metaProp == "og:description" && metaContent != "" {
					description = truncate(metaContent, maxDescriptionLen)
				}
			}

		case html.EndTagToken:
			t := z.Token()
			if strings.ToLower(t.Data) == "title" {
				inTitle = false
			}

		case html.TextToken:
			if inTitle && title == "" {
				title = truncate(strings.TrimSpace(string(z.Text())), maxTitleLen)
			}
		}

		if title != "" && description != "" {
			return strings.TrimSpace(title), strings.TrimSpace(description), nil
		}
	}
}

func truncate(s string, max int) string {
	s = strings.TrimSpace(s)
	if max <= 0 || len(s) <= max {
		return s
	}
	return s[:max]
}

