	ctx.SetStatusCode(status)
	ctx.Response.Header.SetContentType("application/json; charset=utf-8")
	enc := json.NewEncoder(ctx)
	enc.SetEscapeHTML(true)
	_ = enc.Encode(v)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		return
	}

	var req fetchPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchPreviewResponse{Error: "invalid JSON body"})
		return
	}

	raw := strings.TrimSpace(req.URL)
	if raw == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchPreviewResponse{Error: "missing url"})
		return
	}

	u, err := url.Parse(raw)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchPreviewResponse{Error: "invalid url"})
		return
	}
	if u.Scheme == "" {
		u.Scheme = "https"
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchPreviewResponse{Error: "unsupported url scheme"})
		return
	}
	if u.Host == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchPreviewResponse{Error: "invalid url host"})
		return
	}
	target := u.String()

	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         3 * time.Second,
		WriteTimeout:        3 * time.Second,
		MaxResponseBodySize: 1 << 20, // 1MB
	}

	var r fasthttp.Request
	var resp fasthttp.Response
	r.SetRequestURI(target)
	r.Header.SetMethod(fasthttp.MethodGet)
	r.Header.Set("User-Agent", "url-preview-bot/1.0")
	r.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// DoRedirects signature: (req, resp, maxRedirects)
	if err := client.DoRedirects(&r, &resp, 10); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchPreviewResponse{
			URL:   target,
			Error: "fetch failed: " + err.Error(),
		})
		return
	}

	status := resp.StatusCode()
	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchPreviewResponse{
			URL:   target,
			Error: "upstream returned status " + fasthttp.StatusMessage(status),
		})
		return
	}

	ct := strings.ToLower(string(resp.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, fetchPreviewResponse{
			URL:   target,
			Error: "unsupported content-type: " + ct,
		})
		return
	}

	body := resp.Body()
	const maxBody = 1 << 20
	if len(body) > maxBody {
		body = body[:maxBody]
	}

	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(body))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchPreviewResponse{
			URL:   target,
			Error: "failed to parse HTML",
		})
		return
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	desc := ""
	if s := doc.Find(`meta[name="description"]`).First(); s != nil {
		if v, ok := s.Attr("content"); ok {
			desc = strings.TrimSpace(v)
		}
	}
	if desc == "" {
		if s := doc.Find(`meta[property="og:description"]`).First(); s != nil {
			if v, ok := s.Attr("content"); ok {
				desc = strings.TrimSpace(v)
			}
		}
	}

	finalURL := target

	writeJSON(ctx, fasthttp.StatusOK, fetchPreviewResponse{
		URL:         target,
		FinalURL:    finalURL,
		Title:       title,
		Description: desc,
	})
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
		}
	}

	log.Println("listening on :8080 (POST /preview)")
	if err := fasthttp.ListenAndServe(":8080", h); err != nil {
		log.Fatal(err)
	}
}

