func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize to 16-byte for checks (IPv4 mapped handled by To4 below).
	if ip4 := ip.To4(); ip4 != nil {
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1]&0xF0 == 16 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip4[0] == 100 && (ip4[1]&0xC0) == 64 {
			return true
		}
		// 192.0.0.0/24
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 0 {
			return true
		}
		// 192.0.2.0/24 (TEST-NET-1)
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 2 {
			return true
		}
		// 198.18.0.0/15 (benchmarking)
		if ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19) {
			return true
		}
		// 198.51.100.0/24 (TEST-NET-2)
		if ip4[0] == 198 && ip4[1] == 51 && ip4[2] == 100 {
			return true
		}
		// 203.0.113.0/24 (TEST-NET-3)
		if ip4[0] == 203 && ip4[1] == 0 && ip4[2] == 113 {
			return true
		}
		// 224.0.0.0/4 (multicast) and 240.0.0.0/4 (reserved)
		if ip4[0] >= 224 {
			return true
		}
		return false
	}

	// IPv6 checks
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Unique local addresses fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xFE) == 0xFC {
		return true
	}
	// Multicast ff00::/8
	if len(ip) == net.IPv6len && ip[0] == 0xFF {
		return true
	}
	return false
}

func validateURLForSSRF(raw string) (*url.URL, error) {
	u, err := url.Parse(raw)
	if err != nil || u.Scheme == "" || u.Host == "" {
		return nil, errors.New("invalid url")
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		return nil, errors.New("only http/https urls are allowed")
	}

	host := u.Hostname()
	if host == "" {
		return nil, errors.New("invalid url")
	}

	// Block obvious localhost names.
	switch strings.ToLower(host) {
	case "localhost", "localhost.localdomain", "ip6-localhost":
		return nil, errors.New("host is not allowed")
	}

	// If host is an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, errors.New("host is not allowed")
		}
		return u, nil
	}

	// For domain names, resolve and ensure all A/AAAA are public.
	ips, err := net.DefaultResolver.LookupIPAddr(nil, host)
	if err != nil || len(ips) == 0 {
		return nil, errors.New("failed to resolve host")
	}
	for _, ipa := range ips {
		if isPrivateIP(ipa.IP) {
			return nil, errors.New("host is not allowed")
		}
	}

	return u, nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		return
	}

	var req fetchRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchResponse{Error: "invalid json body"})
		return
	}

	raw := strings.TrimSpace(req.URL)
	if raw == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchResponse{Error: "missing url"})
		return
	}

	u, err := validateURLForSSRF(raw)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, fetchResponse{Error: err.Error()})
		return
	}

	// Create a client with a safe dialer that blocks private/loopback/link-local/etc targets.
	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxConnsPerHost:     64,
		MaxIdleConnDuration: 30 * time.Second,
		Dial: func(addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				// addr might already be without port; fallback
				host = addr
				port = ""
			}

			// Validate resolved destination host/IP.
			if ip := net.ParseIP(host); ip != nil {
				if isPrivateIP(ip) {
					return nil, fmt.Errorf("blocked address")
				}
			} else {
				ips, err := net.DefaultResolver.LookupIPAddr(nil, host)
				if err != nil || len(ips) == 0 {
					return nil, fmt.Errorf("resolve failed")
				}
				for _, ipa := range ips {
					if isPrivateIP(ipa.IP) {
						return nil, fmt.Errorf("blocked address")
					}
				}
			}

			target := addr
			if port == "" {
				target = net.JoinHostPort(host, "80")
			}
			d := &net.Dialer{Timeout: 10 * time.Second}
			return d.Dial("tcp", target)
		},
	}

	freq := fasthttp.AcquireRequest()
	fresp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(fresp)

	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.SetRequestURI(u.String())
	freq.Header.Set("User-Agent", "url-preview/1.0 (+fasthttp)")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Avoid following redirects automatically to prevent SSRF via redirects.
	if err := client.Do(freq, fresp); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
			URL:   raw,
			Error: "fetch failed: " + err.Error(),
		})
		return
	}

	status := fresp.StatusCode()

	// Handle redirects manually with validation and a small limit.
	const maxRedirects = 5
	redirects := 0
	for status >= 300 && status < 400 {
		if redirects >= maxRedirects {
			writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
				URL:   raw,
				Error: "too many redirects",
			})
			return
		}
		loc := strings.TrimSpace(string(fresp.Header.Peek("Location")))
		if loc == "" {
			writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
				URL:   raw,
				Error: "redirect missing location",
			})
			return
		}

		nextURL, err := u.Parse(loc)
		if err != nil {
			writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
				URL:   raw,
				Error: "invalid redirect location",
			})
			return
		}

		// Validate the next URL for SSRF before following.
		u, err = validateURLForSSRF(nextURL.String())
		if err != nil {
			writeJSON(ctx, fasthttp.StatusBadRequest, fetchResponse{Error: err.Error()})
			return
		}

		freq.Reset()
		fresp.Reset()
		freq.Header.SetMethod(fasthttp.MethodGet)
		freq.SetRequestURI(u.String())
		freq.Header.Set("User-Agent", "url-preview/1.0 (+fasthttp)")
		freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

		if err := client.Do(freq, fresp); err != nil {
			writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
				URL:   raw,
				Error: "fetch failed: " + err.Error(),
			})
			return
		}

		status = fresp.StatusCode()
		redirects++
	}

	if status < 200 || status >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
			URL:   raw,
			Error: "upstream returned status " + fasthttp.StatusMessage(status),
		})
		return
	}

	ct := strings.ToLower(string(fresp.Header.ContentType()))
	if ct != "" && !strings.Contains(ct, "text/html") && !strings.Contains(ct, "application/xhtml") && !strings.Contains(ct, "xml") {
		writeJSON(ctx, fasthttp.StatusUnsupportedMediaType, fetchResponse{
			URL:   raw,
			Error: "content-type is not html",
		})
		return
	}

	body := fresp.Body()
	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(body))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, fetchResponse{
			URL:   raw,
			Error: "failed to parse html",
		})
		return
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	desc := ""
	if v, ok := doc.Find(`meta[name="description"]`).Attr("content"); ok {
		desc = strings.TrimSpace(v)
	}
	if desc == "" {
		if v, ok := doc.Find(`meta[property="og:description"]`).Attr("content"); ok {
			desc = strings.TrimSpace(v)
		}
	}

	finalURL := u.String()

	writeJSON(ctx, fasthttp.StatusOK, fetchResponse{
		URL:         raw,
		FinalURL:    finalURL,
		Title:       title,
		Description: desc,
	})
}

func main() {
	h := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
		}
	}

	addr := ":8080"
	log.Printf("listening on %s (POST /preview)", addr)
	if err := fasthttp.ListenAndServe(addr, h); err != nil {
		log.Fatal(err)
	}
}

